const staticData = this.getWorkflowStaticData('global');
staticData.sessions = staticData.sessions || {};
staticData.completedIntakes = staticData.completedIntakes || [];

const tgMessage = $json.message ?? $json.edited_message ?? $json;
const chatId = String(tgMessage?.chat?.id ?? tgMessage?.from?.id ?? '').trim();
const text = String(tgMessage?.text ?? tgMessage?.caption ?? '').trim();
const lower = text.toLowerCase();
const firstName = String(tgMessage?.from?.first_name ?? '').trim();
const languageCode = String(tgMessage?.from?.language_code ?? '').trim() || null;

const prompts = [
  'What symptoms are you having?',
  'How long has this been happening?',
  'How severe is it from 1 to 10?',
  'What is your age?',
  'Any red flags like chest pain, trouble breathing, seizure, vomiting blood, or severe bleeding?',
  'What city or area are you in?'
];

if (!chatId) {
  return [{
    json: {
      action: 'ignore',
      chat_id: '',
      channel: 'telegram',
      reply_text: 'I could not read your chat ID. Please send the message again from Telegram.'
    }
  }];
}

if (lower === '/cancel') {
  delete staticData.sessions[chatId];
  return [{
    json: {
      action: 'prompt',
      chat_id: chatId,
      channel: 'telegram',
      reply_text: 'Your triage intake has been cancelled. Send /start to begin again.'
    }
  }];
}

let session = staticData.sessions[chatId] || {
  step: 0,
  data: {
    user_name: firstName || null,
    preferred_language: languageCode,
    channel: 'telegram'
  }
};

const saveSession = () => {
  staticData.sessions[chatId] = session;
};

if (lower === '/start' || lower === 'start') {
  session = {
    step: 0,
    data: {
      user_name: firstName || null,
      preferred_language: languageCode,
      channel: 'telegram'
    }
  };
  saveSession();
  return [{
    json: {
      action: 'prompt',
      chat_id: chatId,
      channel: 'telegram',
      reply_text: 'Welcome. What symptoms are you having?'
    }
  }];
}

if (!text) {
  saveSession();
  return [{
    json: {
      action: 'prompt',
      chat_id: chatId,
      channel: 'telegram',
      reply_text: prompts[session.step] || prompts[0]
    }
  }];
}

switch (session.step) {
  case 0:
    session.data.symptoms = text;
    session.step = 1;
    saveSession();
    return [{ json: { action: 'prompt', chat_id: chatId, channel: 'telegram', reply_text: prompts[1], intake: session.data } }];
  case 1:
    session.data.duration = text;
    session.step = 2;
    saveSession();
    return [{ json: { action: 'prompt', chat_id: chatId, channel: 'telegram', reply_text: prompts[2], intake: session.data } }];
  case 2:
    session.data.severity = text;
    session.step = 3;
    saveSession();
    return [{ json: { action: 'prompt', chat_id: chatId, channel: 'telegram', reply_text: prompts[3], intake: session.data } }];
  case 3:
    session.data.age = text;
    session.step = 4;
    saveSession();
    return [{ json: { action: 'prompt', chat_id: chatId, channel: 'telegram', reply_text: prompts[4], intake: session.data } }];
  case 4:
    session.data.red_flags = text;
    session.step = 5;
    saveSession();
    return [{ json: { action: 'prompt', chat_id: chatId, channel: 'telegram', reply_text: prompts[5], intake: session.data } }];
  case 5: {
    session.data.location = text;
    const intake = {
      ...session.data,
      location: text,
      chat_id: chatId,
      channel: 'telegram',
      collected_at: new Date().toISOString()
    };
    staticData.completedIntakes.push(intake);
    if (staticData.completedIntakes.length > 100) staticData.completedIntakes.shift();
    delete staticData.sessions[chatId];

    const triageMessage = [
      `Symptoms: ${intake.symptoms}`,
      `Duration: ${intake.duration}`,
      `Severity: ${intake.severity}`,
      `Age: ${intake.age}`,
      `Red flags: ${intake.red_flags}`,
      `Location: ${intake.location}`,
      `Language: ${intake.preferred_language || 'unknown'}`
    ].join('\n');

    return [{
      json: {
        action: 'finalize',
        chat_id: chatId,
        channel: 'telegram',
        reply_text: 'Thanks. I am processing your triage now.',
        triage_payload: {
          message: triageMessage,
          channel: 'telegram',
          chat_id: chatId,
          phone_number: null,
          preferred_language: intake.preferred_language,
          facility_location: intake.location,
          offline_mode: false
        },
        intake
      }
    }];
  }
  default:
    session.step = 0;
    saveSession();
    return [{
      json: {
        action: 'prompt',
        chat_id: chatId,
        channel: 'telegram',
        reply_text: prompts[0]
      }
    }];
}

const r = $json;
const mode = String(r.user_mode ?? 'patient');
const urgency = String(r.urgency_level ?? 'standard').toLowerCase();
const score = r.urgency_score ?? '?';
const ticket = r.ticket_id ?? 'N/A';
const report = r.triage_report ?? {};
const diff = Array.isArray(r.differential) && r.differential.length ? r.differential.slice(0, 3).join(', ') : 'Not available';
const actionMap = {
  emergency: 'Go to A&E immediately. Call 112 now.',
  urgent: 'See a doctor within 24 hours.',
  standard: 'Book a clinic appointment this week.',
  'self-care': 'Manage at home with the guidance below.'
};

const summary = [
  'TRIAGE COMPLETE',
  '',
  `Ref: ${ticket}`,
  `Urgency: ${urgency.toUpperCase()} (${score}/10)`,
  `Likely causes: ${diff}`,
  `ACTION: ${actionMap[urgency] || 'See a doctor.'}`,
  '',
  'DISCLAIMER: This is not a substitute for professional medical advice.'
].join('\n');

const reportText = mode === 'clinician'
  ? String(report.clinician_report ?? report.patient_report ?? 'Report unavailable')
  : String(report.patient_report ?? report.emergency_response ?? 'Report unavailable');

const nutrition = urgency === 'self-care' && r.nutrition_advice
  ? `\n\nNIGERIAN NUTRITION ADVICE:\n${r.nutrition_advice}`
  : '';

const progress = urgency === 'self-care'
  ? '\n\nPROGRESS CHECK: You will receive a check-in message in 24 hours.'
  : '';

const disclaimer = '\n\nDISCLAIMER: This is not a substitute for professional medical advice. Always consult a qualified healthcare provider.';

return [{
  json: {
    chat_id: r.chat_id ?? '',
    summary,
    report_text: `${reportText}${nutrition}${progress}${disclaimer}`,
    ticket_id: ticket,
    urgency_level: urgency,
    response_status: r.status ?? 'complete'
  }
}];
